"use client";

import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { useTheme } from "../context/ThemeContext";

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = `
  uniform float uTime;
  uniform vec2 uMouse;
  uniform vec2 uResolution;
  uniform vec3 uColor1;
  uniform vec3 uColor2;
  uniform vec3 uColor3;
  uniform vec3 uBaseColor;
  varying vec2 vUv;

  void main() {
    vec2 uv = vUv;
    float time = uTime * 0.2;
    
    // Parallax shift based on mouse
    vec2 parallax = uMouse * 0.02;
    uv += parallax;

    float d1 = distance(uv, vec2(0.8 + sin(time * 0.5) * 0.2, 0.2 + cos(time * 0.3) * 0.2));
    vec3 color1 = uColor1 * exp(-d1 * 2.5);

    float d2 = distance(uv, vec2(0.2 + cos(time * 0.4) * 0.15, 0.7 + sin(time * 0.6) * 0.15));
    vec3 color2 = uColor2 * exp(-d2 * 3.0);

    float d3 = distance(uv, vec2(0.5 + sin(time * 0.2) * 0.3, 0.5 + cos(time * 0.25) * 0.3));
    vec3 color3 = uColor3 * exp(-d3 * 4.5);

    vec3 finalColor = uBaseColor + (color1 + color2 + color3) * 0.45;

    gl_FragColor = vec4(finalColor, 1.0);
  }
`;

function Scene({ isLight }) {
    const meshRef = useRef();
    const { viewport, size, invalidate } = useThree();
    const [mouse, setMouse] = useState({ x: 0, y: 0 });
    const [reducedMotion, setReducedMotion] = useState(false);

    useEffect(() => {
        const handleMouseMove = (e) => {
            setMouse({
                x: (e.clientX / window.innerWidth - 0.5) * 2,
                y: -(e.clientY / window.innerHeight - 0.5) * 2,
            });
            invalidate(); // Trigger a render implicitly on demand
        };

        const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
        setReducedMotion(mq.matches);
        const listener = (e) => setReducedMotion(e.matches);
        mq.addEventListener("change", listener);

        window.addEventListener("mousemove", handleMouseMove);
        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            mq.removeEventListener("change", listener);
        };
    }, [invalidate]);

    const uniforms = useRef({
        uTime: { value: 0 },
        uMouse: { value: new THREE.Vector2(0, 0) },
        uResolution: { value: new THREE.Vector2(size.width, size.height) },
        uColor1: { value: new THREE.Color() },
        uColor2: { value: new THREE.Color() },
        uColor3: { value: new THREE.Color() },
        uBaseColor: { value: new THREE.Color() },
    }).current;

    useEffect(() => {
        uniforms.uColor1.value.copy(isLight ? new THREE.Color(0.8, 0.9, 1.0) : new THREE.Color(0.23, 0.51, 0.96));
        uniforms.uColor2.value.copy(isLight ? new THREE.Color(0.6, 0.8, 1.0) : new THREE.Color(0.55, 0.36, 0.96));
        uniforms.uColor3.value.copy(isLight ? new THREE.Color(0.4, 0.7, 0.9) : new THREE.Color(0.13, 0.83, 0.93));
        uniforms.uBaseColor.value.copy(isLight ? new THREE.Color(0.97, 0.98, 1.0) : new THREE.Color(0.039, 0.059, 0.11));
        invalidate();
    }, [isLight, uniforms, invalidate]);

    useFrame((state) => {
        const time = state.clock.getElapsedTime();
        uniforms.uTime.value = reducedMotion ? time * 0.1 : time;

        // Smooth mouse follow
        uniforms.uMouse.value.x = THREE.MathUtils.lerp(uniforms.uMouse.value.x, mouse.x, 0.05);
        uniforms.uMouse.value.y = THREE.MathUtils.lerp(uniforms.uMouse.value.y, mouse.y, 0.05);
    });

    return (
        <mesh ref={meshRef} scale={[viewport.width, viewport.height, 1]}>
            <planeGeometry args={[1, 1]} />
            <shaderMaterial
                vertexShader={vertexShader}
                fragmentShader={fragmentShader}
                uniforms={uniforms}
            />
        </mesh>
    );
}

export default function Background3D() {
    const { theme } = useTheme();
    const isLight = theme === 'light';

    return (
        <div
            className="bg-3d-surface"
            style={{
                position: "fixed",
                inset: 0,
                zIndex: -1,
                pointerEvents: "none",
                background: isLight ? "linear-gradient(135deg, #F8FBFF, #EAF4FF, #F3F8FF)" : "#0A0F1C",
                transition: "background 0.4s ease"
            }}
        >
            <Canvas camera={{ position: [0, 0, 1] }} frameloop="demand" dpr={[1, 1.5]}>
                <Scene isLight={isLight} />
            </Canvas>
        </div>
    );
}

"use client";

import React from 'react';
import styles from './Certifications.module.css';
import GlowCard from './GlowCard';
import { certificationsData } from '@/utils/data/certifications-data';
import useScrollReveal from '@/utils/hooks/useScrollReveal';

const Certifications = () => {
    const containerRef = useScrollReveal(0.2); // Trigger when 20% visible for better UX

    return (
        <section className={styles.section} ref={containerRef}>
            <div className={styles.container}>
                <h2 className={styles.heading}>Professional <span className="text-secondary-color">Certifications</span></h2>
                <div className={styles.grid}>
                    {certificationsData.map((cert, index) => (
                        <div key={index} className="fromLeft" style={{ transitionDelay: `${index * 0.1}s` }}>
                            <GlowCard>
                                <a
                                    href={cert.link}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className={styles.card}
                                >
                                    <div
                                        className={styles.banner}
                                        style={{ backgroundColor: cert.bannerColor }}
                                    >
                                        <div className={styles.overlay}>
                                            <span className={styles.overlayText}>View Certificate</span>
                                        </div>
                                        {cert.issuerDomain ? (
                                            <img
                                                src={`https://logo.clearbit.com/${cert.issuerDomain}`}
                                                alt={cert.issuer}
                                                className={styles.logo}
                                                onError={(e) => {
                                                    e.target.style.display = 'none';
                                                    e.target.nextSibling.style.display = 'block';
                                                }}
                                            />
                                        ) : (
                                            <img
                                                src={cert.logoUrl}
                                                alt={cert.issuer}
                                                className={styles.logo}
                                            />
                                        )}
                                        <span className={styles.fallbackText}>{cert.issuer}</span>
                                    </div>
                                    <div className={styles.content}>
                                        <h3 className={styles.title}>{cert.title}</h3>
                                        <span className={styles.issuer}>— {cert.issuer}</span>
                                    </div>
                                </a>
                            </GlowCard>
                        </div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default Certifications;

